<html lang="zh-CN">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>《无畏契约》战绩分析</title>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            font-family: 'Arial', 'Helvetica Neue', sans-serif;
            background: linear-gradient(135deg, #0a0e27 0%, #1a1f3a 100%);
            color: #e0e0e0;
            overflow-x: hidden;
        }

        /* ========== 导航栏 ========== */
        nav {
            background: rgba(10, 14, 39, 0.95);
            border-bottom: 2px solid #ff4655;
            padding: 0 40px;
            height: 70px;
            display: flex;
            justify-content: space-between;
            align-items: center;
            box-shadow: 0 4px 20px rgba(255, 70, 85, 0.2);
            position: sticky;
            top: 0;
            z-index: 1000;
        }

        .logo {
            font-size: 24px;
            font-weight: bold;
            background: linear-gradient(90deg, #ff4655, #ff6b7a);
            -webkit-background-clip: text;
            -webkit-text-fill-color: transparent;
            background-clip: text;
            letter-spacing: 2px;
        }

        nav ul {
            display: flex;
            list-style: none;
            gap: 40px;
        }

        nav a {
            color: #e0e0e0;
            text-decoration: none;
            font-size: 14px;
            font-weight: 500;
            transition: all 0.3s ease;
            position: relative;
        }

        nav a:hover {
            color: #ff4655;
        }

        nav a::after {
            content: '';
            position: absolute;
            bottom: -5px;
            left: 0;
            width: 0;
            height: 2px;
            background: #ff4655;
            transition: width 0.3s ease;
        }

        nav a:hover::after {
            width: 100%;
        }

        /* ========== 主容器 ========== */
        .container {
            max-width: 1920px;
            margin: 0 auto;
            padding: 40px 40px;
        }

        /* ========== 英雄展示区 ========== */
        .hero-section {
            display: grid;
            grid-template-columns: 1fr 1fr;
            gap: 60px;
            margin-bottom: 60px;
            align-items: center;
        }

        .hero-image-container {
            position: relative;
            height: 500px;
            overflow: hidden;
            border-radius: 10px;
            box-shadow: 0 10px 40px rgba(255, 70, 85, 0.3);
        }

        .hero-image {
            width: 100%;
            height: 100%;
            background: linear-gradient(135deg, #1a1f3a, #2a2f4a);
            display: flex;
            align-items: center;
            justify-content: center;
            font-size: 120px;
            transition: all 0.5s ease;
            position: relative;
            overflow: hidden;
        }

        .hero-image::before {
            content: '';
            position: absolute;
            top: -50%;
            right: -50%;
            width: 200%;
            height: 200%;
            background: radial-gradient(circle, rgba(255, 70, 85, 0.1) 0%, transparent 70%);
            animation: glow 3s ease-in-out infinite;
        }

        @keyframes glow {
            0%, 100% { transform: translate(0, 0); }
            50% { transform: translate(20px, 20px); }

